mapper.select:
select question_id, title, content, views, q_regdate, q_regip, ans, ansdate, ansip, user_id, user_name, lect_id, lect_name, inst_id, inst_name from (select q.question_id, q.title, q.content, q.views, q.regdate as q_regdate, q.regip as q_regip, q.ans, q.ansdate, q.ansip, q.user_id, u.name as user_name, q.lect_id, l.name as lect_name, l.inst_id, i.name as inst_name, row_number() over(order by q.regdate desc) rnum from question q left outer join users u on q.user_id = u.user_id left outer join lecture l on q.lect_id = l.lect_id left outer join instructor i on l.inst_id = i.inst_id
instr(${fieldStr}, #{keyword}) != 0
) where rnum between #{startNum} and #{endNum}
